begin;
create table if not exists public.platform_events(id uuid primary key default gen_random_uuid(),slug text not null unique,title text not null,description text not null,audience text[] not null default '{}',event_type text not null check(event_type in ('webinar','workshop','career_clinic','hiring_drive','networking')),starts_at timestamptz not null,ends_at timestamptz not null,mode text not null check(mode in ('online','offline','hybrid')),venue text,meeting_link text,capacity integer check(capacity is null or capacity>0),price numeric(12,2) not null default 0,status text not null default 'draft' check(status in ('draft','published','cancelled','completed')),created_by uuid references public.users(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),check(ends_at>starts_at));
create table if not exists public.event_registrations(id uuid primary key default gen_random_uuid(),event_id uuid not null references public.platform_events(id) on delete cascade,user_id uuid not null references public.users(id) on delete cascade,status text not null default 'registered' check(status in ('registered','attended','cancelled','no_show')),payment_status text not null default 'not_required' check(payment_status in ('not_required','pending','paid','refunded')),registered_at timestamptz not null default now(),unique(event_id,user_id));
create table if not exists public.career_passports(user_id uuid primary key references public.users(id) on delete cascade,public_slug text not null unique,headline text,summary text,visibility text not null default 'private' check(visibility in ('private','public')),open_to_opportunities boolean not null default false,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.career_passport_items(id uuid primary key default gen_random_uuid(),user_id uuid not null references public.users(id) on delete cascade,item_type text not null check(item_type in ('skill','project','achievement','experience','education','credential')),title text not null,issuer text,description text,evidence_url text,issued_on date,expires_on date,verification_status text not null default 'self_declared' check(verification_status in ('self_declared','pending','verified','rejected')),verified_by uuid references public.users(id),verified_at timestamptz,sort_order integer not null default 0,created_at timestamptz not null default now());
create index if not exists events_status_start_idx on public.platform_events(status,starts_at);create index if not exists passport_items_user_idx on public.career_passport_items(user_id,item_type,sort_order);
alter table public.platform_events enable row level security;alter table public.event_registrations enable row level security;alter table public.career_passports enable row level security;alter table public.career_passport_items enable row level security;
create policy "Published events visible" on public.platform_events for select to anon,authenticated using(status in ('published','completed'));
create policy "Users view registrations" on public.event_registrations for select to authenticated using(user_id=auth.uid());create policy "Users register events" on public.event_registrations for insert to authenticated with check(user_id=auth.uid() and status='registered');create policy "Users cancel registrations" on public.event_registrations for update to authenticated using(user_id=auth.uid()) with check(user_id=auth.uid() and status='cancelled');
create policy "Users view own or public passport" on public.career_passports for select to anon,authenticated using(user_id=auth.uid() or visibility='public');create policy "Users create own passport" on public.career_passports for insert to authenticated with check(user_id=auth.uid());create policy "Users update own passport" on public.career_passports for update to authenticated using(user_id=auth.uid()) with check(user_id=auth.uid());
create policy "Users view own items or public passport items" on public.career_passport_items for select to anon,authenticated using(user_id=auth.uid() or exists(select 1 from public.career_passports p where p.user_id=career_passport_items.user_id and p.visibility='public'));create policy "Users add own passport items" on public.career_passport_items for insert to authenticated with check(user_id=auth.uid() and verification_status='self_declared');create policy "Users update own unverified items" on public.career_passport_items for update to authenticated using(user_id=auth.uid() and verification_status<>'verified') with check(user_id=auth.uid() and verification_status in ('self_declared','pending'));create policy "Users delete own unverified items" on public.career_passport_items for delete to authenticated using(user_id=auth.uid() and verification_status<>'verified');
insert into public.career_passports(user_id,public_slug) select id,lower(regexp_replace(coalesce(full_name,'member'),'[^a-zA-Z0-9]','-','g'))||'-'||substr(replace(id::text,'-',''),1,6) from public.users on conflict(user_id) do nothing;
create or replace function public.create_career_passport() returns trigger language plpgsql security definer set search_path=public as $$begin insert into public.career_passports(user_id,public_slug) values(new.id,lower(regexp_replace(coalesce(new.full_name,'member'),'[^a-zA-Z0-9]','-','g'))||'-'||substr(replace(new.id::text,'-',''),1,6)) on conflict(user_id) do nothing;return new;end$$;drop trigger if exists create_career_passport_after_user on public.users;create trigger create_career_passport_after_user after insert on public.users for each row execute function public.create_career_passport();
commit;
